input.command:
kubectl exec -n elasticsearch es-0 -- curl -sf --cacert /usr/share/elasticsearch/config/certs/ca.crt \
  -u "elastic:elasticpass" \
  -X PUT "https://localhost:9200/_snapshot/minio-repo" \
  -H "Content-Type: application/json" \
  -d '{
    "type": "s3",
    "settings": {
      "bucket": "es-backups",
      "endpoint": "minio.elasticsearch.svc.cluster.local:9000",
      "protocol": "http",
      "path_style_access": true
    }
  }' 2>&1 | python3 -m json.tool
